19	// fakeDeferredBinder is the injected listen seam (m.deferredListen) the reconcile
20	// tests drive: it returns EADDRNOTAVAIL — the "source_addr not yet assignable" signal
21	// reconcileDeferred reads to keep a path deferred — until arm() is called, after which
22	// it binds a real loopback socket (the address "became assignable"). The returned
23	// socket is adopted by m.paths on a successful promote and closed by m.Close, so the
24	// seam leaks nothing. It is safe for the single-goroutine synchronous test driver.
25	type fakeDeferredBinder struct {
26		mu    sync.Mutex
27		armed bool
28	}
29	
30	func (f *fakeDeferredBinder) arm() {
31		f.mu.Lock()
32		f.armed = true
33		f.mu.Unlock()
34	}
35	
36	func (f *fakeDeferredBinder) listen(_ netip.Addr, _ uint16) (*net.UDPConn, error) {
37		f.mu.Lock()
38		armed := f.armed
39		f.mu.Unlock()
40		if !armed {
41			// Exactly the error a real not-yet-assignable source_addr yields; reconcileDeferred
42			// keeps the path deferred and retries next tick.
43			return nil, syscall.EADDRNOTAVAIL
44		}
45		// The address is now assignable: bind a real loopback socket standing in for the
46		// interface that just came up, so the promoted path has a working transport the test
47		// can probe over.
48		return net.ListenUDP("udp", &net.UDPAddr{IP: net.ParseIP("127.0.0.1")})
49	}
50	
51	// TestReconcilePromotesDeferredPathToLive is the T55 core acceptance: a path DEFERRED
52	// at Open because its source_addr was not assignable (EADDRNOTAVAIL) is BOUND and
53	// PROMOTED to a live path by the background reconcile once the address becomes
54	// assignable — brought into m.paths, the scheduler, and its reader — so the scheduler
55	// then selects it, WITHOUT a Close→Open restart. It also asserts the promoted path
56	// reuses its deferred boot prober (id-stamp continuity, T51). The promotion assertion
57	// FAILS on the pre-T55 code, which has no reconcile: a deferred path stays Down forever.
58	func TestReconcilePromotesDeferredPathToLive(t *testing.T) {
59		psk := testKey(t, 0x55)
60		clk := newFakeClock()
61		paths := []config.Path{
62			{Name: "bindable", SourceAddr: netip.MustParseAddr("127.0.0.1")},
63			{Name: "deferred", SourceAddr: netip.MustParseAddr(unassignableSource)},
64		}
65		m, probers, scheduler := newProbingMultipath(t, paths, psk, clk)
66		binder := &fakeDeferredBinder{}
67		m.deferredListen = binder.listen
68	
69		if _, _, err := m.Open(0); err != nil {
70			t.Fatalf("Open: %v", err)
71		}
72		t.Cleanup(func() { _ = m.Close() })
73	
74		// Precondition (T51): path 1 is deferred, not live.
75		if len(m.paths) != 1 || len(m.deferred) != 1 {
76			t.Fatalf("after Open: paths=%d deferred=%d, want 1 and 1", len(m.paths), len(m.deferred))
77		}
78	
79		// Reconcile while the address is STILL unassignable: nothing is promoted, the path
80		// stays deferred and is retried.
81		m.reconcileDeferred()
82		if len(m.paths) != 1 || len(m.deferred) != 1 {
83			t.Fatalf("reconcile before the address is assignable promoted a path: paths=%d deferred=%d", len(m.paths), len(m.deferred))
84		}
85	
86		// The source_addr BECOMES assignable; the next reconcile binds and promotes it.
87		binder.arm()
88		m.reconcileDeferred()
89		if len(m.paths) != 2 {
90			t.Fatalf("live paths after reconcile = %d, want 2 (deferred path promoted)", len(m.paths))
91		}
92		if len(m.deferred) != 0 {
93			t.Fatalf("deferred set after promote = %d, want 0", len(m.deferred))
94		}
95		promoted := m.paths[1]
96		if promoted.name != "deferred" {
97			t.Fatalf("promoted path name = %q, want %q", promoted.name, "deferred")
98		}
99		if promoted.conn == nil {
100			t.Fatal("promoted path has no socket")
101		}
102		// Stamp continuity (T51): the promoted path reuses its deferred boot prober, so its
103		// id-stamp is unchanged and its prober is the SAME object the scheduler selects on.
104		if promoted.prober != probers[1] {
105			t.Fatal("promoted path did not reuse its deferred boot prober (stamp continuity lost)")
106		}
107		if promoted.id != probers[1].PathID() {
108			t.Fatalf("promoted path id = %d, want its reserved prober stamp %d", promoted.id, probers[1].PathID())
109		}
110	
111		// The promoted path is now in the SCHEDULER: bring both paths Up, blackhole the
112		// original primary, and assert egress fails over to the promoted path — only possible
113		// if reconcile admitted it to the scheduler as a live, selectable path.
114		refl := telemetry.NewReflector(psk, rand.Reader)
115		codec, _ := frame.NewCodec(psk)
116		peer0, ap0 := rawPeer(t)
117		peer1, ap1 := rawPeer(t)
118		m.paths[0].setRemote(ap0)
119		promoted.setRemote(ap1)
120		for i := 0; i < testProbeUpSucc; i++ {
121			probeRound(t, m, clk, refl, codec, psk,
122				map[int]*net.UDPConn{0: peer0, 1: peer1}, map[int]netip.AddrPort{0: ap0, 1: ap1})
123		}
124		if promoted.prober.State() != telemetry.StateUp {
125			t.Fatalf("promoted path state = %v, want up (probes not driving its liveness)", promoted.prober.State())
126		}
127		if idx := scheduler.Pick(sched.ClassData); idx != 0 {
128			t.Fatalf("Pick = %d while both up, want the primary 0", idx)
129		}
130	
131		// Blackhole the primary: drop its echoes, keep echoing the promoted path. After the
132		// detection window the primary goes Down and the scheduler fails egress over to the
133		// promoted path (index 1).
134		rounds := int(testProbeDownAfter/testProbeInterval) + 3
135		for i := 0; i < rounds; i++ {
136			m.emitProbes()
137			clk.advance(testProbeRTT)
138			_ = readProbe(t, peer0, codec) // primary blackholed: drain its probe, do not echo
139			probe1 := readProbe(t, peer1, codec)
140			raw, err := frame.Encode(psk, probe1)
141			if err != nil {
142				t.Fatalf("re-encode probe: %v", err)
143			}
144			echo, err := refl.Reflect(raw)
145			if err != nil {
146				t.Fatalf("reflect promoted path: %v", err)
147			}
148			m.handleInbound(m.paths[1], echo, ap1)
149			clk.advance(testProbeInterval - testProbeRTT)
150		}
151		if probers[0].State() != telemetry.StateDown {
152			t.Fatalf("blackholed primary state = %v, want down", probers[0].State())
153		}
154		if idx := scheduler.Pick(sched.ClassData); idx != 1 {
155			t.Fatalf("Pick = %d after primary blackhole, want failover to the promoted path 1", idx)
156		}
157		// The failover is usable end to end: a Send routes over the promoted path.
158		if err := m.Send([][]byte{[]byte("post-promote")}, m.virt); err != nil {
159			t.Fatalf("Send over the promoted path: %v", err)
160		}
161	}
162	
163	// TestReconcileSkipsPathRemovedBeforeBind is the race guard: a deferred path removed
164	// (a config reload drops it) BEFORE it ever binds must NOT be resurrected by a later
165	// reconcile once its address becomes assignable. RemovePath retires it from the
166	// deferred set, so reconcile has nothing to promote.
167	func TestReconcileSkipsPathRemovedBeforeBind(t *testing.T) {
168		psk := testKey(t, 0x56)
169		clk := newFakeClock()
170		paths := []config.Path{
171			{Name: "bindable", SourceAddr: netip.MustParseAddr("127.0.0.1")},
172			{Name: "deferred", SourceAddr: netip.MustParseAddr(unassignableSource)},
173		}
174		m, _, _ := newProbingMultipath(t, paths, psk, clk)
175		binder := &fakeDeferredBinder{}
176		m.deferredListen = binder.listen
177	
178		if _, _, err := m.Open(0); err != nil {
179			t.Fatalf("Open: %v", err)
180		}
181		t.Cleanup(func() { _ = m.Close() })
182	
183		if len(m.deferred) != 1 {
184			t.Fatalf("after Open: deferred = %d, want 1", len(m.deferred))
185		}
186		// The still-deferred path is dropped by a reload before it ever bound.
187		if err := m.RemovePath("deferred"); err != nil {
188			t.Fatalf("RemovePath(deferred): %v", err)
189		}
190		if len(m.deferred) != 0 {
191			t.Fatalf("deferred after remove = %d, want 0 (removal retires it)", len(m.deferred))
192		}
193	
194		// Its address now becomes assignable; reconcile must NOT resurrect the removed path.
195		binder.arm()
196		m.reconcileDeferred()
197		if len(m.paths) != 1 {
198			t.Fatalf("live paths = %d after reconcile, want 1 (a removed deferred path must not be promoted)", len(m.paths))
199		}
200		for _, ps := range m.paths {
201			if ps.name == "deferred" {
202				t.Fatal("a path removed before it bound was promoted by reconcile")
203			}
204		}
205	}
206	
207	// TestReconcileLoopStopsCleanly asserts the background reconcile goroutine terminates
208	// on its stopper with no goroutine leak (the shutdown contract Close relies on), and
209	// that the stopper is idempotent. goleak.VerifyNone fails if the loop goroutine
210	// outlives stop().
211	func TestReconcileLoopStopsCleanly(t *testing.T) {
212		defer goleak.VerifyNone(t)
213		psk := testKey(t, 0x57)
214		clk := newFakeClock()
215		m, _, _ := newProbingMultipath(t, loopbackPaths(1), psk, clk)
216		if _, _, err := m.Open(0); err != nil {
217			t.Fatalf("Open: %v", err)
218		}
219	
220		stop := m.StartReconcileLoop(1 * time.Millisecond)
221		time.Sleep(10 * time.Millisecond) // let it tick a few times against the empty deferred set
222		stop()
223		stop() // idempotent
224	
225		if err := m.Close(); err != nil {
226			t.Fatalf("Close: %v", err)
227		}
228	}
