230	// TestReconcileLoopNoopWithoutProbeTransport asserts a bind without the probe transport
231	// (no probers — the T12 unit binds, which never defer) gets a no-op reconcile loop and
232	// stopper, so nothing is started to leak.
233	func TestReconcileLoopNoopWithoutProbeTransport(t *testing.T) {
234		defer goleak.VerifyNone(t)
235		psk := testKey(t, 0x58)
236		m, err := newMultipath(t, loopbackPaths(1), psk)
237		if err != nil {
238			t.Fatalf("NewMultipath: %v", err)
239		}
240		stop := m.StartReconcileLoop(1 * time.Millisecond)
241		stop() // must be safe: no goroutine was started
242	}
