// i's specific source IP. A snapshot failure resolves every source to an empty
// dev, so all paths fall back to source-IP binding.
func planPathBinds(srcs []netip.Addr) []string {
	ifaces, err := net.Interfaces()
	if err != nil {
		ifaces = nil
