		if infos[i].dev != "" {
			devPaths[infos[i].dev]++
		}
	}
	out := make([]string, len(srcs))
	for i := range srcs {
		info := infos[i]
		if info.dev != "" && info.familyCount == 1 && devPaths[info.dev] == 1 {
			out[i] = info.dev
		}
	}
	return out
}

