	shared := &sharedPathState{name: dp.def.Name, id: dp.prober.PathID(), src: dp.def.SourceAddr, conn: c}
	ps := &peerPathState{sharedPathState: shared, peer: m.peerState, codec: codec, prober: dp.prober}
